1	import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
2	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
3	
4	const ALLOWED_ORIGINS = [
5	  "https://crevia.app",
6	  "https://www.crevia.app",
7	  "http://localhost:8080",
8	  "http://localhost:5173",
9	  "https://creviamvp.vercel.app",
10	];
11	
12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get("Origin") ?? "";
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    "Access-Control-Allow-Origin": allowed,
17	    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
18	    "Vary": "Origin",
19	  };
20	}
21	
22	function formatCurrency(amount: number, currency: string): string {
23	  return new Intl.NumberFormat("en-KE", { style: "currency", currency }).format(amount);
24	}
25	
26	function formatDate(dateStr: string): string {
27	  return new Date(dateStr).toLocaleDateString("en-GB", {
28	    day: "2-digit", month: "short", year: "numeric",
29	  });
30	}
31	
32	serve(async (req) => {
33	  const cors = getCorsHeaders(req);
34	
35	  if (req.method === "OPTIONS") {
36	    return new Response(null, { headers: cors });
37	  }
38	
39	  if (req.method !== "POST") {
40	    return new Response(JSON.stringify({ error: "Method not allowed" }), {
41	      status: 405, headers: { ...cors, "Content-Type": "application/json" },
42	    });
43	  }
44	
45	  const authHeader = req.headers.get("Authorization");
46	  if (!authHeader?.startsWith("Bearer ")) {
47	    return new Response(JSON.stringify({ error: "Unauthorized" }), {
48	      status: 401, headers: { ...cors, "Content-Type": "application/json" },
49	    });
50	  }
51	
52	  const resendKey = Deno.env.get("RESEND_API_KEY");
53	  if (!resendKey) {
54	    return new Response(JSON.stringify({ error: "Email service not configured" }), {
55	      status: 500, headers: { ...cors, "Content-Type": "application/json" },
56	    });
57	  }
58	
59	  try {
60	    const { contract_id } = await req.json();
61	    if (!contract_id) {
62	      return new Response(JSON.stringify({ error: "contract_id required" }), {
63	        status: 400, headers: { ...cors, "Content-Type": "application/json" },
64	      });
65	    }
66	
67	    // User-scoped client: anon key + caller's JWT so PostgREST uses auth.uid() for RLS
68	    const userClient = createClient(
69	      Deno.env.get("SUPABASE_URL")!,
70	      Deno.env.get("SUPABASE_ANON_KEY")!,
71	      { global: { headers: { Authorization: authHeader } } },
72	    );
73	
74	    // Admin client: service role for writes that cross user boundaries
75	    const adminClient = createClient(
76	      Deno.env.get("SUPABASE_URL")!,
77	      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!,
78	    );
79	
80	    // Fetch contract as the authenticated user — RLS ensures they can only see their own
81	    const { data: contract, error: conErr } = await userClient
82	      .from("contracts")
83	      .select("*")
84	      .eq("id", contract_id)
85	      .single();
86	
87	    if (conErr || !contract) {
88	      return new Response(JSON.stringify({ error: "Contract not found" }), {
89	        status: 404, headers: { ...cors, "Content-Type": "application/json" },
90	      });
91	    }
92	
93	    if (!contract.client_email) {
94	      return new Response(JSON.stringify({ error: "No client email on this contract" }), {
95	        status: 400, headers: { ...cors, "Content-Type": "application/json" },
96	      });
97	    }
98	
99	    // Fetch sender profile + business settings
100	    const [{ data: profile }, { data: biz }] = await Promise.all([
101	      userClient.from("profiles").select("display_name, email").single(),
102	      userClient.from("business_settings").select("*").maybeSingle(),
103	    ]);
104	
105	    const senderName = biz?.business_name || profile?.display_name || "Crevia User";
106	    const senderEmail = biz?.business_email || profile?.email || "";
107	    const currency = contract.currency || "KES";
108	
109	    const deliverablesHtml = Array.isArray(contract.deliverables) && contract.deliverables.length
110	      ? `<ul style="margin:8px 0 0;padding-left:20px;">${contract.deliverables.map((d: string) =>
111	          `<li style="font-size:13px;color:#444;margin-bottom:4px;">${d}</li>`
112	        ).join("")}</ul>`
113	      : "";
114	
115	    const html = `
116	<!DOCTYPE html>
117	<html lang="en">
118	<head>
119	  <meta charset="UTF-8" />
120	  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
121	  <title>Contract: ${contract.title}</title>
122	</head>
123	<body style="margin:0;padding:0;background:#f5f4f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">
124	  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f4f0;padding:40px 16px;">
125	    <tr>
126	      <td align="center">
127	        <table width="100%" cellpadding="0" cellspacing="0" style="max-width:580px;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">
128	
129	          <!-- Header -->
130	          <tr>
131	            <td style="background:#1a1a1a;padding:28px 40px;">
132	              <table width="100%"><tr>
133	                <td>
134	                  <table cellpadding="0" cellspacing="0"><tr>
135	                    <td style="vertical-align:middle;padding-right:10px;">
136	                      <img src="https://creviamvp.vercel.app/crevia-logo.png" alt="Crevia" width="40" height="40" style="display:block;border-radius:50%;border:1px solid #333;" />
137	                    </td>
138	                    <td style="vertical-align:middle;">
139	                      <span style="font-size:22px;font-weight:700;color:#c9a96e;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">Crevia</span>
140	                    </td>
141	                  </tr></table>
142	                </td>
143	                <td align="right">
144	                  <p style="margin:0;font-size:13px;color:#888;">Contract</p>
145	                  <p style="margin:2px 0 0;font-size:16px;font-weight:700;color:#fff;">${contract.title}</p>
146	                </td>
147	              </tr></table>
148	            </td>
149	          </tr>
150	
151	          <!-- Parties -->
152	          <tr>
153	            <td style="padding:28px 40px 0;">
154	              <table width="100%"><tr>
155	                <td style="vertical-align:top;">
156	                  <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">From</p>
157	                  <p style="margin:0;font-size:14px;font-weight:600;color:#111;">${senderName}</p>
158	                  ${senderEmail ? `<p style="margin:2px 0 0;font-size:13px;color:#666;">${senderEmail}</p>` : ""}
159	                </td>
160	                <td style="vertical-align:top;" align="right">
161	                  <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">To</p>
162	                  <p style="margin:0;font-size:14px;font-weight:600;color:#111;">${contract.client_name}</p>
163	                  <p style="margin:2px 0 0;font-size:13px;color:#666;">${contract.client_email}</p>
164	                </td>
165	              </tr></table>
166	            </td>
167	          </tr>
168	
169	          <!-- Key Terms -->
170	          <tr>
171	            <td style="padding:20px 40px 0;">
172	              <table width="100%" cellpadding="0" cellspacing="0">
173	                <tr>
174	                  <td style="background:#f9f7f3;border-radius:8px;padding:16px 20px;">
175	                    <table width="100%">
176	                      <tr>
177	                        ${contract.start_date ? `<td>
178	                          <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Start Date</p>
179	                          <p style="margin:0;font-size:14px;font-weight:500;color:#333;">${formatDate(contract.start_date)}</p>
180	                        </td>` : ""}
181	                        ${contract.end_date ? `<td align="center">
182	                          <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">End Date</p>
183	                          <p style="margin:0;font-size:14px;font-weight:600;color:#c9a96e;">${formatDate(contract.end_date)}</p>
184	                        </td>` : ""}
185	                        ${contract.value ? `<td align="right">
186	                          <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Contract Value</p>
187	                          <p style="margin:0;font-size:18px;font-weight:700;color:#111;">${formatCurrency(contract.value, currency)}</p>
188	                        </td>` : ""}
189	                      </tr>
190	                    </table>
191	                  </td>
192	                </tr>
193	              </table>
194	            </td>
195	          </tr>
196	
197	          <!-- Deliverables -->
198	          ${deliverablesHtml ? `
199	          <tr>
200	            <td style="padding:20px 40px 0;">
201	              <p style="margin:0 0 6px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Deliverables</p>
202	              ${deliverablesHtml}
203	            </td>
204	          </tr>` : ""}
205	
206	          <!-- Payment Terms -->
207	          ${contract.payment_terms ? `
208	          <tr>
209	            <td style="padding:16px 40px 0;">
210	              <p style="margin:0 0 6px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Payment Terms</p>
211	              <p style="margin:0;font-size:13px;color:#444;line-height:1.6;">${contract.payment_terms}</p>
212	            </td>
213	          </tr>` : ""}
214	
215	          <!-- CTA -->
216	          <tr>
217	            <td style="padding:28px 40px;">
218	              <table width="100%"><tr><td align="center">
219	                <a href="https://creviamvp.vercel.app/received?tab=contracts&id=${contract_id}" style="display:inline-block;background:#c9a96e;color:#fff;text-decoration:none;padding:14px 32px;border-radius:8px;font-weight:700;font-size:15px;">
220	                  View &amp; Sign Contract
221	                </a>
222	              </td></tr></table>
223	            </td>
224	          </tr>
225	
226	          <!-- Footer -->
227	          <tr>
228	            <td style="padding:0 40px 32px;border-top:1px solid #f0ede8;">
229	              <p style="margin:16px 0 0;font-size:12px;color:#aaa;line-height:1.7;">
230	                This contract was sent via <strong style="color:#c9a96e;">Crevia</strong> · creviamvp.vercel.app<br/>
231	                Log in to your Crevia account to review and sign.
232	              </p>
233	            </td>
234	          </tr>
235	
236	        </table>
237	      </td>
238	    </tr>
239	  </table>
240	</body>
241	</html>`;
242	
243	    // Send email via Resend
244	    const emailRes = await fetch("https://api.resend.com/emails", {
245	      method: "POST",
246	      headers: {
247	        "Authorization": `Bearer ${resendKey}`,
248	        "Content-Type": "application/json",
249	      },
250	      body: JSON.stringify({
251	        from: `${senderName} via Crevia <contracts@crevia.app>`,
252	        to: contract.client_email,
253	        reply_to: senderEmail || undefined,
254	        subject: `Contract from ${senderName}: ${contract.title}`,
255	        html,
256	      }),
257	    });
258	
259	    if (!emailRes.ok) {
260	      const errBody = await emailRes.text();
261	      console.error("Resend error:", errBody);
262	      let resendMsg = "Failed to send email";
263	      try { resendMsg = JSON.parse(errBody)?.message || resendMsg; } catch {}
264	      return new Response(JSON.stringify({ error: resendMsg }), {
265	        status: 500, headers: { ...cors, "Content-Type": "application/json" },
266	      });
267	    }
268	
269	    // Mark contract as sent
270	    await adminClient
271	      .from("contracts")
272	      .update({ status: "sent" })
273	      .eq("id", contract_id);
274	
275	    // Notify client if they have a Crevia account
276	    const { data: clientProfile } = await adminClient
277	      .from("profiles")
278	      .select("id")
279	      .eq("email", contract.client_email)
280	      .maybeSingle();
281	
282	    if (clientProfile?.id) {
283	      await adminClient.from("notifications").insert({
284	        user_id: clientProfile.id,
285	        type: "contract_received",
286	        title: `Contract from ${senderName}`,
287	        body: `You have received a contract: "${contract.title}". Review and sign it on Crevia.`,
288	        data: { contract_id, link: "/received" },
289	      });
290	    }
291	
292	    return new Response(JSON.stringify({ sent: true }), {
293	      status: 200, headers: { ...cors, "Content-Type": "application/json" },
294	    });
295	
296	  } catch (err) {
297	    console.error("contract-send error:", err);
298	    return new Response(JSON.stringify({ error: "Internal server error" }), {
299	      status: 500, headers: { ...cors, "Content-Type": "application/json" },
300	    });
301	  }
302	});
