1	import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
2	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
3	
4	const ALLOWED_ORIGINS = [
5	  'https://crevia.app',
6	  'https://www.crevia.app',
7	  'http://localhost:8080',
8	  'http://localhost:5173',
9	  'https://creviamvp.vercel.app',
10	];
11	
12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get('Origin') ?? '';
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    'Access-Control-Allow-Origin': allowed,
17	    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
18	    'Vary': 'Origin',
19	  };
20	}
21	
22	const VALID_CONTRACT_TYPES = ['sponsorship', 'content_creation', 'brand_ambassador', 'ugc', 'affiliate', 'custom'];
23	const VALID_STATUSES = ['draft', 'sent', 'signed', 'active', 'completed', 'cancelled'];
24	
25	serve(async (req) => {
26	  const cors = getCorsHeaders(req);
27	
28	  if (req.method === 'OPTIONS') {
29	    return new Response(null, { headers: cors });
30	  }
31	
32	  if (req.method !== 'POST') {
33	    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
34	      status: 405,
35	      headers: { ...cors, 'Content-Type': 'application/json' },
36	    });
37	  }
38	
39	  try {
40	    // === AUTH VALIDATION ===
41	    const authHeader = req.headers.get('Authorization');
42	    if (!authHeader?.startsWith('Bearer ')) {
43	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
44	        status: 401,
45	        headers: { ...cors, 'Content-Type': 'application/json' },
46	      });
47	    }
48	
49	    const supabase = createClient(
50	      Deno.env.get('SUPABASE_URL')!,
51	      Deno.env.get('SUPABASE_ANON_KEY')!,
52	      { global: { headers: { Authorization: authHeader } } }
53	    );
54	
55	    const token = authHeader.replace('Bearer ', '');
56	    const { data: claimsData, error: claimsError } = await supabase.auth.getClaims(token);
57	    if (claimsError || !claimsData?.claims) {
58	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
59	        status: 401,
60	        headers: { ...cors, 'Content-Type': 'application/json' },
61	      });
62	    }
63	
64	    const userId = claimsData.claims.sub;
65	    // === END AUTH VALIDATION ===
66	
67	    // === RATE LIMIT (10 requests per 60 seconds per user) ===
68	    const { data: allowed } = await supabase.rpc('check_rate_limit', {
69	      p_user_id:     userId,
70	      p_endpoint:    'contracts-create',
71	      p_limit:       10,
72	      p_window_secs: 60,
73	    });
74	    if (!allowed) {
75	      return new Response(JSON.stringify({ error: 'Too many requests. Please slow down.' }), {
76	        status: 429,
77	        headers: { ...cors, 'Content-Type': 'application/json' },
78	      });
79	    }
80	    // === END RATE LIMIT ===
81	
82	    // === PLAN LIMIT GATE (free: 2 contracts/month) ===
83	    const { data: profile } = await supabase
84	      .from('profiles')
85	      .select('subscription_plan')
86	      .eq('id', userId)
87	      .single();
88	
89	    const isFreePlan = !profile?.subscription_plan || profile.subscription_plan === 'free';
90	
91	    if (isFreePlan) {
92	      const startOfMonth = new Date();
93	      startOfMonth.setDate(1);
94	      startOfMonth.setHours(0, 0, 0, 0);
95	
96	      const { count } = await supabase
97	        .from('contracts')
98	        .select('id', { count: 'exact', head: true })
99	        .eq('user_id', userId)
100	        .gte('created_at', startOfMonth.toISOString());
101	
102	      if ((count ?? 0) >= 2) {
103	        return new Response(JSON.stringify({
104	          error: 'Free plan limit reached. Upgrade to Pro for unlimited contracts.',
105	          code: 'PLAN_LIMIT_REACHED',
106	        }), {
107	          status: 403,
108	          headers: { ...cors, 'Content-Type': 'application/json' },
109	        });
110	      }
111	    }
112	    // === END PLAN LIMIT GATE ===
113	
114	    // === INPUT VALIDATION ===
115	    let body: Record<string, unknown>;
116	    try {
117	      body = await req.json();
118	    } catch {
119	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
120	        status: 400,
121	        headers: { ...cors, 'Content-Type': 'application/json' },
122	      });
123	    }
124	
125	    const { title, client_name, contract_type, status, client_email, start_date, end_date,
126	            value, currency, content, deliverables, payment_terms, exclusivity,
127	            exclusivity_details, usage_rights, termination_clause } = body as Record<string, unknown>;
128	
129	    if (!title || typeof title !== 'string' || title.trim().length === 0) {
130	      return new Response(JSON.stringify({ error: 'title is required' }), {
131	        status: 400,
132	        headers: { ...cors, 'Content-Type': 'application/json' },
133	      });
134	    }
135	
136	    if (!client_name || typeof client_name !== 'string' || client_name.trim().length === 0) {
137	      return new Response(JSON.stringify({ error: 'client_name is required' }), {
138	        status: 400,
139	        headers: { ...cors, 'Content-Type': 'application/json' },
140	      });
141	    }
142	
143	    const resolvedType = (typeof contract_type === 'string' && VALID_CONTRACT_TYPES.includes(contract_type))
144	      ? contract_type : 'custom';
145	
146	    const resolvedStatus = (typeof status === 'string' && VALID_STATUSES.includes(status))
147	      ? status : 'draft';
148	    // === END INPUT VALIDATION ===
149	
150	    const { data: contract, error: insertError } = await supabase
151	      .from('contracts')
152	      .insert({
153	        user_id: userId,
154	        title: (title as string).trim(),
155	        client_name: (client_name as string).trim(),
156	        contract_type: resolvedType,
157	        status: resolvedStatus,
158	        client_email: typeof client_email === 'string' ? client_email.trim() : null,
159	        start_date: typeof start_date === 'string' ? start_date : null,
160	        end_date: typeof end_date === 'string' ? end_date : null,
161	        value: typeof value === 'number' ? value : null,
162	        currency: typeof currency === 'string' ? currency : 'KES',
163	        content: typeof content === 'string' ? content : null,
164	        deliverables: Array.isArray(deliverables) ? deliverables : null,
165	        payment_terms: typeof payment_terms === 'string' ? payment_terms : null,
166	        exclusivity: typeof exclusivity === 'boolean' ? exclusivity : false,
167	        exclusivity_details: typeof exclusivity_details === 'string' ? exclusivity_details : null,
168	        usage_rights: typeof usage_rights === 'string' ? usage_rights : null,
169	        termination_clause: typeof termination_clause === 'string' ? termination_clause : null,
170	      })
171	      .select()
172	      .single();
173	
174	    if (insertError) {
175	      console.error('contracts-create insert error:', insertError);
176	      return new Response(JSON.stringify({ error: 'Failed to create contract' }), {
177	        status: 500,
178	        headers: { ...cors, 'Content-Type': 'application/json' },
179	      });
180	    }
181	
182	    return new Response(JSON.stringify({ contract }), {
183	      status: 201,
184	      headers: { ...cors, 'Content-Type': 'application/json' },
185	    });
186	
187	  } catch (error) {
188	    console.error('contracts-create error:', error);
189	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
190	      status: 500,
191	      headers: { ...cors, 'Content-Type': 'application/json' },
192	    });
193	  }
194	});
