34	  sent: ['paid', 'overdue', 'cancelled'],
35	  overdue: ['paid', 'cancelled'],
36	  paid: [],
37	  cancelled: [],
38	};
39	
40	serve(async (req) => {
41	  const cors = getCorsHeaders(req);
42	
43	  if (req.method === 'OPTIONS') {
44	    return new Response(null, { headers: cors });
45	  }
46	
47	  if (req.method !== 'POST') {
48	    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
49	      status: 405,
50	      headers: { ...cors, 'Content-Type': 'application/json' },
51	    });
52	  }
53	
54	  try {
55	    // === AUTH VALIDATION ===
56	    const authHeader = req.headers.get('Authorization');
57	    if (!authHeader?.startsWith('Bearer ')) {
58	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
59	        status: 401,
60	        headers: { ...cors, 'Content-Type': 'application/json' },
61	      });
62	    }
63	
64	    const supabase = createClient(
65	      Deno.env.get('SUPABASE_URL')!,
66	      Deno.env.get('SUPABASE_ANON_KEY')!,
67	      { global: { headers: { Authorization: authHeader } } }
68	    );
69	
70	    const token = authHeader.replace('Bearer ', '');
71	    const { data: claimsData, error: claimsError } = await supabase.auth.getClaims(token);
72	    if (claimsError || !claimsData?.claims) {
73	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
74	        status: 401,
75	        headers: { ...cors, 'Content-Type': 'application/json' },
76	      });
77	    }
78	
79	    const userId = claimsData.claims.sub;
80	    // === END AUTH VALIDATION ===
81	
82	    // === INPUT VALIDATION ===
83	    let body: Record<string, unknown>;
84	    try {
85	      body = await req.json();
86	    } catch {
87	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
88	        status: 400,
89	        headers: { ...cors, 'Content-Type': 'application/json' },
90	      });
91	    }
92	
93	    const { document_type, document_id, new_status } = body as Record<string, unknown>;
94	
95	    if (document_type !== 'contract' && document_type !== 'invoice') {
96	      return new Response(JSON.stringify({ error: 'document_type must be "contract" or "invoice"' }), {
97	        status: 400,
98	        headers: { ...cors, 'Content-Type': 'application/json' },
99	      });
100	    }
101	
102	    if (!document_id || typeof document_id !== 'string') {
103	      return new Response(JSON.stringify({ error: 'document_id is required' }), {
104	        status: 400,
105	        headers: { ...cors, 'Content-Type': 'application/json' },
106	      });
107	    }
108	
109	    if (!new_status || typeof new_status !== 'string') {
110	      return new Response(JSON.stringify({ error: 'new_status is required' }), {
111	        status: 400,
112	        headers: { ...cors, 'Content-Type': 'application/json' },
113	      });
114	    }
115	    // === END INPUT VALIDATION ===
116	
117	    const table = document_type === 'contract' ? 'contracts' : 'invoices';
118	    const transitions = document_type === 'contract' ? CONTRACT_TRANSITIONS : INVOICE_TRANSITIONS;
119	
120	    // Fetch the current record (RLS ensures it belongs to this user)
121	    const { data: record, error: fetchError } = await supabase
122	      .from(table)
123	      .select('id, status, user_id')
124	      .eq('id', document_id)
125	      .eq('user_id', userId)
126	      .single();
127	
128	    if (fetchError || !record) {
129	      return new Response(JSON.stringify({ error: 'Document not found' }), {
130	        status: 404,
131	        headers: { ...cors, 'Content-Type': 'application/json' },
132	      });
133	    }
134	
135	    // Enforce valid transition
136	    const allowedNext = transitions[record.status] ?? [];
137	    if (!allowedNext.includes(new_status as string)) {
138	      return new Response(JSON.stringify({
139	        error: `Cannot transition from "${record.status}" to "${new_status}". Allowed: ${allowedNext.join(', ') || 'none'}`,
140	      }), {
141	        status: 422,
142	        headers: { ...cors, 'Content-Type': 'application/json' },
143	      });
144	    }
145	
146	    // Apply the status update
147	    const { data: updated, error: updateError } = await supabase
148	      .from(table)
149	      .update({ status: new_status, updated_at: new Date().toISOString() })
150	      .eq('id', document_id)
151	      .eq('user_id', userId)
152	      .select()
153	      .single();
154	
155	    if (updateError) {
156	      console.error('approve-action update error:', updateError);
157	      return new Response(JSON.stringify({ error: 'Failed to update status' }), {
158	        status: 500,
159	        headers: { ...cors, 'Content-Type': 'application/json' },
160	      });
161	    }
162	
163	    return new Response(JSON.stringify({ document: updated }), {
164	      status: 200,
165	      headers: { ...cors, 'Content-Type': 'application/json' },
166	    });
167	
168	  } catch (error) {
169	    console.error('approve-action error:', error);
170	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
171	      status: 500,
172	      headers: { ...cors, 'Content-Type': 'application/json' },
173	    });
174	  }
175	});
