21	// ─── Types ────────────────────────────────────────────────────────────────────
22	
23	interface SigPos { x: number; y: number; w: number; h: number }
24	
25	const MIN_W   = 80;
26	const MIN_H   = 40;
27	const INIT_W  = 220;
28	const INIT_H  = 88;
29	
30	// ─── Draggable + resizable widget ─────────────────────────────────────────────
31	// Must live outside ContractPreviewDialog so React never unmounts it on parent
32	// re-renders during an active drag.
33	
34	interface DraggableSigProps {
35	  pos:       SigPos;
36	  signature: string;
37	  onChange:  (p: SigPos) => void;
38	}
39	
40	const DraggableSig = ({ pos, signature, onChange }: DraggableSigProps) => {
41	  const dragRef   = useRef<{ sx: number; sy: number; ox: number; oy: number } | null>(null);
42	  const resizeRef = useRef<{ corner: string; sx: number; sy: number; orig: SigPos } | null>(null);
43	
44	  // drag body
45	  const onBodyDown = (e: React.PointerEvent<HTMLDivElement>) => {
46	    e.preventDefault();
47	    e.stopPropagation();
48	    e.currentTarget.setPointerCapture(e.pointerId);
49	    dragRef.current = { sx: e.clientX, sy: e.clientY, ox: pos.x, oy: pos.y };
50	  };
51	  const onBodyMove = (e: React.PointerEvent<HTMLDivElement>) => {
52	    if (!dragRef.current) return;
53	    onChange({ ...pos, x: dragRef.current.ox + (e.clientX - dragRef.current.sx), y: dragRef.current.oy + (e.clientY - dragRef.current.sy) });
54	  };
55	  const onBodyUp = () => { dragRef.current = null; };
56	
57	  // resize corners
58	  const ch = (corner: string) => ({
59	    onPointerDown: (e: React.PointerEvent<HTMLDivElement>) => {
60	      e.preventDefault();
61	      e.stopPropagation();
62	      e.currentTarget.setPointerCapture(e.pointerId);
63	      resizeRef.current = { corner, sx: e.clientX, sy: e.clientY, orig: { ...pos } };
64	    },
65	    onPointerMove: (e: React.PointerEvent<HTMLDivElement>) => {
66	      if (!resizeRef.current || resizeRef.current.corner !== corner) return;
67	      const dx = e.clientX - resizeRef.current.sx;
68	      const dy = e.clientY - resizeRef.current.sy;
69	      const o  = resizeRef.current.orig;
70	      let { x, y, w, h } = o;
71	      if (corner === "se") { w = Math.max(MIN_W, o.w + dx);                                 h = Math.max(MIN_H, o.h + dy); }
72	      if (corner === "sw") { x = o.x + Math.min(dx, o.w - MIN_W); w = Math.max(MIN_W, o.w - dx); h = Math.max(MIN_H, o.h + dy); }
73	      if (corner === "ne") { w = Math.max(MIN_W, o.w + dx); y = o.y + Math.min(dy, o.h - MIN_H); h = Math.max(MIN_H, o.h - dy); }
74	      if (corner === "nw") {
75	        x = o.x + Math.min(dx, o.w - MIN_W); w = Math.max(MIN_W, o.w - dx);
76	        y = o.y + Math.min(dy, o.h - MIN_H); h = Math.max(MIN_H, o.h - dy);
77	      }
78	      onChange({ x, y, w, h });
79	    },
80	    onPointerUp: () => { resizeRef.current = null; },
81	  });
82	
83	  const corners = [
84	    { id: "nw", cls: "-top-2 -left-2 cursor-nw-resize" },
85	    { id: "ne", cls: "-top-2 -right-2 cursor-ne-resize" },
86	    { id: "sw", cls: "-bottom-2 -left-2 cursor-sw-resize" },
87	    { id: "se", cls: "-bottom-2 -right-2 cursor-se-resize" },
88	  ];
89	
90	  const fs = Math.max(14, Math.min(pos.h * 0.40, 48));
91	
92	  return (
93	    <div
94	      className="absolute touch-none select-none"
95	      style={{ left: pos.x, top: pos.y, width: pos.w, height: pos.h, zIndex: 60 }}
96	      onClick={e => e.stopPropagation()}
97	    >
98	      {/* body */}
99	      <div
100	        className="w-full h-full rounded-lg border-2 border-dashed border-primary/60 flex items-center justify-center overflow-hidden cursor-move"
101	        onPointerDown={onBodyDown}
102	        onPointerMove={onBodyMove}
103	        onPointerUp={onBodyUp}
104	      >
105	        {signature.startsWith("data:image") ? (
106	          <img src={signature} alt="sig" className="max-w-full max-h-full object-contain p-1 mix-blend-multiply dark:mix-blend-screen" draggable={false} />
107	        ) : (
108	          <span className="font-vollkorn italic text-foreground/85 truncate px-2 pointer-events-none" style={{ fontSize: fs }}>
109	            {signature}
110	          </span>
111	        )}
112	      </div>
113	
114	      {/* corner resize handles */}
115	      {corners.map(({ id, cls }) => (
116	        <div
117	          key={id}
118	          className={cn("absolute w-4 h-4 bg-white border-2 border-primary rounded-sm shadow-md touch-none z-10", cls)}
119	          {...ch(id)}
120	        />
121	      ))}
122	    </div>
123	  );
124	};
