1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	
4	export type SubscriptionPlan = "free" | "creative_pro" | "brand_workspace";
5	
6	export interface SubscriptionLimits {
7	  kiraActionsPerDay: number;
8	  invoicesPerMonth: number;
9	  contractsPerMonth: number;
10	  hasESignature: boolean;
11	  hasPremiumThemes: boolean;
12	  hasClientPortal: boolean;
13	  hasVerifiedBadge: boolean;
14	  hasFullAnalytics: boolean;
15	  hasUnlimitedInvoices: boolean;
16	  hasUnlimitedContracts: boolean;
17	}
18	
19	export interface SubscriptionState {
20	  plan: SubscriptionPlan;
21	  status: string;
22	  isLoading: boolean;
23	  isPro: boolean;
24	  isBrandWorkspace: boolean;
25	  isFree: boolean;
26	  limits: SubscriptionLimits;
27	  kiraActionsToday: number;
28	  kiraActionsLimit: number;
29	  invoicesUsedThisMonth: number;
30	  contractsUsedThisMonth: number;
31	}
32	
33	const PLAN_LIMITS: Record<SubscriptionPlan, SubscriptionLimits> = {
34	  free: {
35	    kiraActionsPerDay: 10,
36	    invoicesPerMonth: 2,
37	    contractsPerMonth: 2,
38	    hasESignature: false,
39	    hasPremiumThemes: false,
40	    hasClientPortal: false,
41	    hasVerifiedBadge: false,
42	    hasFullAnalytics: false,
43	    hasUnlimitedInvoices: false,
44	    hasUnlimitedContracts: false,
45	  },
46	  creative_pro: {
47	    kiraActionsPerDay: 40,
48	    invoicesPerMonth: Infinity,
49	    contractsPerMonth: Infinity,
50	    hasESignature: true,
51	    hasPremiumThemes: true,
52	    hasClientPortal: true,
53	    hasVerifiedBadge: true,
54	    hasFullAnalytics: true,
55	    hasUnlimitedInvoices: true,
56	    hasUnlimitedContracts: true,
57	  },
58	  brand_workspace: {
59	    kiraActionsPerDay: 40,
60	    invoicesPerMonth: Infinity,
61	    contractsPerMonth: Infinity,
62	    hasESignature: true,
63	    hasPremiumThemes: true,
64	    hasClientPortal: true,
65	    hasVerifiedBadge: true,
66	    hasFullAnalytics: true,
67	    hasUnlimitedInvoices: true,
68	    hasUnlimitedContracts: true,
69	  },
70	};
71	
72	// A plan only grants Pro/Workspace features when the subscription is active or trialing.
73	const ACTIVE_STATUSES = new Set(["active", "trialing"]);
74	
75	export const useSubscription = (): SubscriptionState => {
76	  const [plan, setPlan] = useState<SubscriptionPlan>("free");
77	  const [status, setStatus] = useState("inactive");
78	  const [isLoading, setIsLoading] = useState(true);
79	  const [kiraActionsToday, setKiraActionsToday] = useState(0);
80	  const [kiraActionsLimit, setKiraActionsLimit] = useState(10);
81	  const [invoicesUsedThisMonth, setInvoicesUsedThisMonth] = useState(0);
82	  const [contractsUsedThisMonth, setContractsUsedThisMonth] = useState(0);
83	
84	  const applyProfile = (profile: Record<string, unknown>) => {
85	    setPlan((profile.subscription_plan as SubscriptionPlan) || "free");
86	    setStatus((profile.subscription_status as string) || "inactive");
87	    setKiraActionsToday((profile.kira_actions_used as number) || 0);
88	    setKiraActionsLimit((profile.kira_actions_limit as number) || 10);
89	    setInvoicesUsedThisMonth((profile.invoices_used_this_month as number) || 0);
90	    setContractsUsedThisMonth((profile.contracts_used_this_month as number) || 0);
91	  };
92	
93	  useEffect(() => {
94	    let channel: ReturnType<typeof supabase.channel> | null = null;
95	
96	    const setup = async () => {
97	      const { data: { user } } = await supabase.auth.getUser();
98	      if (!user) {
99	        setIsLoading(false);
100	        return;
101	      }
102	
103	      const { data: profile } = await supabase
104	        .from("profiles")
105	        .select("subscription_plan, subscription_status, kira_actions_used, kira_actions_limit, invoices_used_this_month, contracts_used_this_month")
106	        .eq("id", user.id)
107	        .single();
108	
109	      if (profile) applyProfile(profile as Record<string, unknown>);
110	      setIsLoading(false);
111	
112	      // Real-time listener: fires the moment the Paystack webhook updates the profile row.
113	      channel = supabase
114	        .channel(`subscription:${user.id}`)
115	        .on(
116	          "postgres_changes",
117	          {
118	            event: "UPDATE",
119	            schema: "public",
120	            table: "profiles",
121	            filter: `id=eq.${user.id}`,
122	          },
123	          (payload) => {
124	            applyProfile(payload.new as Record<string, unknown>);
125	          }
126	        )
127	        .subscribe();
128	    };
129	
130	    setup();
131	
132	    return () => {
133	      if (channel) supabase.removeChannel(channel);
134	    };
135	  }, []);
136	
137	  const currentPlan = plan || "free";
138	  const limits = PLAN_LIMITS[currentPlan];
139	  const isActiveStatus = ACTIVE_STATUSES.has(status);
140	
141	  return {
142	    plan: currentPlan,
143	    status,
144	    isLoading,
145	    isPro: currentPlan === "creative_pro" && isActiveStatus,
146	    isBrandWorkspace: currentPlan === "brand_workspace" && isActiveStatus,
147	    isFree: currentPlan === "free" || !isActiveStatus,
148	    limits,
149	    kiraActionsToday,
150	    kiraActionsLimit,
151	    invoicesUsedThisMonth,
152	    contractsUsedThisMonth,
153	  };
154	};
