58	export function ApproveActionDialog({ open, onOpenChange }: ApproveActionDialogProps) {
59	  const [docType, setDocType] = useState<'contract' | 'invoice'>('contract');
60	  const [contracts, setContracts] = useState<Document[]>([]);
61	  const [invoices, setInvoices] = useState<Document[]>([]);
62	  const [selectedId, setSelectedId] = useState<string>('');
63	  const [selectedStatus, setSelectedStatus] = useState<string>('');
64	  const [isLoading, setIsLoading] = useState(false);
65	  const [isFetching, setIsFetching] = useState(false);
66	  const [done, setDone] = useState(false);
67	
68	  useEffect(() => {
69	    if (!open) {
70	      setSelectedId('');
71	      setSelectedStatus('');
72	      setDone(false);
73	      return;
74	    }
75	    fetchDocuments();
76	  }, [open]);
77	
78	  const fetchDocuments = async () => {
79	    setIsFetching(true);
80	    const [contractsRes, invoicesRes] = await Promise.all([
81	      supabase.from('contracts').select('id, title, client_name, status').not('status', 'in', '("completed","cancelled")').order('updated_at', { ascending: false }),
82	      supabase.from('invoices').select('id, invoice_number, client_name, status').not('status', 'in', '("paid","cancelled")').order('updated_at', { ascending: false }),
83	    ]);
84	    if (contractsRes.data) setContracts(contractsRes.data);
85	    if (invoicesRes.data) setInvoices(invoicesRes.data);
86	    setIsFetching(false);
87	  };
88	
89	  const docs = docType === 'contract' ? contracts : invoices;
90	  const selectedDoc = docs.find(d => d.id === selectedId);
91	  const transitions = selectedDoc
92	    ? (docType === 'contract' ? CONTRACT_TRANSITIONS : INVOICE_TRANSITIONS)[selectedDoc.status] ?? []
93	    : [];
94	
95	  const handleApprove = async () => {
96	    if (!selectedId || !selectedStatus) return;
97	    setIsLoading(true);
98	
99	    const { data: { session } } = await supabase.auth.getSession();
100	    if (!session) {
101	      toast.error('Not authenticated');
102	      setIsLoading(false);
103	      return;
104	    }
105	
106	    try {
107	      const res = await fetch(
108	        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/approve-action`,
109	        {
110	          method: 'POST',
111	          headers: {
112	            'Content-Type': 'application/json',
113	            Authorization: `Bearer ${session.access_token}`,
114	          },
115	          body: JSON.stringify({
116	            document_type: docType,
117	            document_id: selectedId,
118	            new_status: selectedStatus,
119	          }),
120	        }
121	      );
122	
123	      const json = await res.json();
124	      if (!res.ok) {
125	        toast.error(json.error || 'Failed to update status');
126	      } else {
127	        setDone(true);
128	        toast.success(`${docType === 'contract' ? 'Contract' : 'Invoice'} updated to "${selectedStatus}"`);
129	        // Refresh lists
130	        await fetchDocuments();
131	      }
132	    } catch {
133	      toast.error('Something went wrong. Please try again.');
134	    } finally {
135	      setIsLoading(false);
136	    }
137	  };
138	
139	  return (
140	    <Dialog open={open} onOpenChange={onOpenChange}>
141	      <DialogContent className="sm:max-w-md">
142	        <DialogHeader>
143	          <DialogTitle>Approve or Update a Document</DialogTitle>
144	          <DialogDescription>
145	            Select a contract or invoice and move it to the next stage.
146	          </DialogDescription>
147	        </DialogHeader>
148	
149	        {done ? (
150	          <div className="flex flex-col items-center gap-3 py-6">
151	            <CheckCircle2 className="w-12 h-12 text-green-500" />
152	            <p className="text-sm font-medium">Status updated successfully</p>
153	            <Button variant="outline" onClick={() => { setDone(false); setSelectedId(''); setSelectedStatus(''); }}>
154	              Update another
155	            </Button>
156	          </div>
157	        ) : (
158	          <div className="space-y-4 py-2">
159	            {/* Document type toggle */}
160	            <div className="flex rounded-lg border border-border/50 overflow-hidden">
161	              <button
162	                onClick={() => { setDocType('contract'); setSelectedId(''); setSelectedStatus(''); }}
163	                className={`flex-1 flex items-center justify-center gap-2 py-2.5 text-sm font-medium transition-colors ${
164	                  docType === 'contract' ? 'bg-bronze text-background' : 'hover:bg-muted/50 text-muted-foreground'
165	                }`}
166	              >
167	                <FileSignature className="w-4 h-4" />
168	                Contracts
169	              </button>
170	              <button
171	                onClick={() => { setDocType('invoice'); setSelectedId(''); setSelectedStatus(''); }}
172	                className={`flex-1 flex items-center justify-center gap-2 py-2.5 text-sm font-medium transition-colors ${
173	                  docType === 'invoice' ? 'bg-bronze text-background' : 'hover:bg-muted/50 text-muted-foreground'
174	                }`}
175	              >
176	                <Receipt className="w-4 h-4" />
177	                Invoices
178	              </button>
179	            </div>
180	
181	            {isFetching ? (
182	              <div className="flex items-center justify-center py-6">
183	                <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
184	              </div>
185	            ) : docs.length === 0 ? (
186	              <p className="text-sm text-muted-foreground text-center py-4">
187	                No active {docType}s found.
188	              </p>
189	            ) : (
190	              <>
191	                {/* Document select */}
192	                <div className="space-y-1.5">
193	                  <label className="text-sm font-medium">Select {docType}</label>
194	                  <Select value={selectedId} onValueChange={(v) => { setSelectedId(v); setSelectedStatus(''); }}>
195	                    <SelectTrigger>
196	                      <SelectValue placeholder={`Choose a ${docType}...`} />
197	                    </SelectTrigger>
