206	                            <span className={`text-xs capitalize ml-auto ${STATUS_COLORS[doc.status]}`}>
207	                              {doc.status}
208	                            </span>
209	                          </div>
210	                        </SelectItem>
211	                      ))}
212	                    </SelectContent>
213	                  </Select>
214	                </div>
215	
216	                {/* Action select */}
217	                {selectedId && transitions.length > 0 && (
218	                  <div className="space-y-1.5">
219	                    <label className="text-sm font-medium">Action</label>
220	                    <Select value={selectedStatus} onValueChange={setSelectedStatus}>
